  ('BILE DUCTS','bile_ducts_1','AND SPLENIC DISORDERS','intrahepatic biliary system runs parallel to portal venous supply of liver SUBVESICAL / ACCESSORY BILE DUCTS small ducts from liver bed draining directly into GB TRIANGLE OF CALOT anatomic space bordered by CHD medially, cystic duct inferiorly, and cystic artery','distal cystic duct posterior to CBD (in 95%), anterior to CBD (in 5%)','distal cystic duct posterior to CBD (in 95%), anterior to CBD (in 5%)','{"Genetics": "PKHD1 (polycystic kidney hepatic disease 1) gene codes for", "Pathology": "mutation of PKHD1 gene → abnormal cilia → abnormal ductal plate formation", "Prevalence": "2.4% of autopsies; 13-18.5% of operative cholangiograms", "Incidence": "2%"}','{"distal cystic duct posterior to CBD (in 95%), anterior to CBD (in 5%)","almost horizontal course","more vertical course","pneumobilia","cystic duct parallels extrahepatic bile duct (implies common fibrous sheath)"}','{"general": [], "Cystic duct": ["distal cystic duct posterior to CBD (in 95%), anterior to CBD (in 5%)", "almost horizontal course", "more vertical course", "pneumobilia", "cystic duct parallels extrahepatic bile duct (implies common fibrous sheath)", "gallbladder drains directly into common bile duct"]}','{"N.B.": "important for donor of right hepatic lobe transplant", "Cx": "during cholecystectomy"}','processed_clusters/disease_entries/and_splenic_disorders/bile_ducts_1.md'),
  ('BILE LEAK','bile_leak','AND SPLENIC DISORDERS','','DIAGNOSTIC but with poor anatomic definition and spatial resolution necessitating a','depicts peripheral sites of leakage that may not be filled with retrograde injection','{"Prevalence": "7% after laparoscopic cholecystectomy"}','{"DIAGNOSTIC but with poor anatomic definition and spatial resolution necessitating a","dynamic biliary imaging during hepatobiliary phase with improved characterization of","depicts peripheral sites of leakage that may not be filled with retrograde injection"}','{"general": ["DIAGNOSTIC but with poor anatomic definition and spatial resolution necessitating a", "dynamic biliary imaging during hepatobiliary phase with improved characterization of", "depicts peripheral sites of leakage that may not be filled with retrograde injection"]}','{"Prognosis": "high morbidity + mortality rates if undiagnosed", "Rx": "endoscopic / surgical management"}','processed_clusters/disease_entries/and_splenic_disorders/bile_leak.md'),
  ('BILIARY CYSTADENOCARCINOMA','biliary_cystadenocarcinoma','AND SPLENIC DISORDERS','BILE DUCT CYSTADENOCARCINOMA rare malignant multilocular cystic tumor originating from biliary cystadenoma','nodularity with septations are suggestive of malignancy','','{}','{"nodularity with septations are suggestive of malignancy","coarse calcifications"}','{"general": ["nodularity with septations are suggestive of malignancy", "coarse calcifications"]}','{}','processed_clusters/disease_entries/and_splenic_disorders/biliary_cystadenocarcinoma.md'),
  ('BILIARY CYSTADENOMA','biliary_cystadenoma','AND SPLENIC DISORDERS','BILE DUCT CYSTADENOMA very rare benign multilocular cystic tumor originating in bile ducts as premalignant form of','multiloculated mass of near water density','intrahepatic÷extrahepatic bile ducts = 85÷15; right lobe (48%); left lobe (20-35%);','{"Frequency": "4.6% of all intrahepatic cysts of bile duct origin", "Age": "> 30 years (82%), peak incidence in 5th decade; M÷F = 1÷4; predominantly in", "Path": "multilocular cystic tumor containing proteinaceous fluid with well-defined thick capsule", "Histo": "single layer of cuboidal / tall columnar mucin-secreting biliary-type epithelium with", "Location": "intrahepatic÷extrahepatic bile ducts = 85÷15; right lobe (48%); left lobe (20-35%);", "Size": "1.5-35 cm (reportedly up to 11 liters of liquid content)"}','{"well-defined cystic mass containing clear / cloudy, serous / mucinous / gelatinous, purulent /","thick fibrous capsule","papillary excrescences + mural nodules","septations between cysts","multiloculated mass of near water density"}','{"general": ["well-defined cystic mass containing clear / cloudy, serous / mucinous / gelatinous, purulent /", "thick fibrous capsule", "papillary excrescences + mural nodules", "septations between cysts"], "US": ["ovoid multiloculated anechoic mass with highly echogenic septations / papillary growths", "may contain fluid-fluid levels"], "CT": ["multiloculated mass of near water density", "contrast enhancement in wall + internal septa"], "MR": ["locules with variable SI on T1WI + T2WI depending on their protein content"], "ANGIO": ["avascular mass with small clusters of peripheral abnormal vessels", "stretching + displacement of vessels", "thin subtle blush of neovascularity in septa + wall"]}','{"Rx": "surgical resection (recurrence common)"}','processed_clusters/disease_entries/and_splenic_disorders/biliary_cystadenoma.md'),
