  ('CORTICAL CONTUSION','cortical_contusion','CENTRAL NEUROCYTOMA','CEREBRAL CONTUSION = BRAIN CONTUSION traumatic injury to cortical surface of brain','"salt and pepper lesion" = mottled / speckled densities as focal / multiple (29%) poorly','multiple bilateral lesions;','{"Incidence": "most common type of primary intraaxial lesion; in 21% of head trauma patients;", "Path": "petechial hemorrhage (= admixture of blood with native tissue) followed by liquefaction", "Associated with": "skull fracture", "Location": "multiple bilateral lesions;"}','{"\"salt and pepper lesion\" = mottled / speckled densities as focal / multiple (29%) poorly","diffuse cerebral hypodensity + swelling without hemorrhage in immediate posttraumatic","some degree of contrast enhancement ← leaking new capillaries","hemorrhage isodense after 2-3 weeks","true extent of lesions becomes more evident with progression of edema + cell necrosis +"}','{"general": ["\"salt and pepper lesion\" = mottled / speckled densities as focal / multiple (29%) poorly", "diffuse cerebral hypodensity + swelling without hemorrhage in immediate posttraumatic", "some degree of contrast enhancement ← leaking new capillaries", "hemorrhage isodense after 2-3 weeks", "true extent of lesions becomes more evident with progression of edema + cell necrosis +", "hemorrhagic lesion (detected in 50% of all contusions):", "initially decreased intensity (← deoxyhemoglobin of acute hemorrhage) surrounded by", "hyperintense on T1WI + T2WI in subacute phase ← Met-Hb", "hyperintense gliosis + hypointense hemosiderin on T2WI in chronic phase", "nonhemorrhagic lesion hypointense on T1WI + hyperintense on T2WI"]}','{"Cx": "(1)  Progression to cerebral hematoma"}','processed_clusters/disease_entries/central_neurocytoma/cortical_contusion.md'),
  ('CREUTZFELDT-JACOB DISEASE','creutzfeldt_jacob_disease','CENTRAL NEUROCYTOMA','rare subacutely progressive neurological disorder due to transmissible infectious disease','usually normal','cerebral cortex, basal ganglia (caudate nucleus), thalamus','{"Age": "older adults (57-73 years)", "Histo": "classified as spongiform encephalopathy \"mad cow disease\"", "Location": "cerebral cortex, basal ganglia (caudate nucleus), thalamus"}','{"usually normal","rapidly progressive atrophic changes","hyperintense T2 lesions in basal ganglia (head of caudate nucleus + putamen), occipital","high-SI lesions on DWI (← vacuolization of neutrophil leading to gliosis + astrocytosis and","restricted diffusion is more sensitive than T2-FLAIR, especially for cortical lesions ←"}','{"general": [], "CT": ["usually normal", "rapidly progressive atrophic changes"], "MR": ["hyperintense T2 lesions in basal ganglia (head of caudate nucleus + putamen), occipital", "high-SI lesions on DWI (← vacuolization of neutrophil leading to gliosis + astrocytosis and", "restricted diffusion is more sensitive than T2-FLAIR, especially for cortical lesions ←", "\"pulvinar\" sign / \"hockey stick\" sign = T2 prolongation + restricted diffusion in medial", "NO gadolinium enhancement of lesions", "NO white matter involvement"]}','{"Prognosis": "usually fatal within 2 year of onset of symptoms (mean, 8.8 months)"}','processed_clusters/disease_entries/central_neurocytoma/creutzfeldt_jacob_disease.md'),
